import './AvatarText.scss';

import React from 'react';

import { classNames } from '../../helpers/classnames';
import { Avatar } from '../Avatar';
import { Informer } from '../Informer';
import { Typography } from '../Typography';
import type { AvatarTextProps } from './AvatarText.types';

export const AvatarText: React.FC<AvatarTextProps> = ({
	size = 'default',
	avatarProps,
	informerProps,
	label,
	description,
	suffix,
	className,
	dataTestId = 'AvatarText',
	...props
}) => {
	// Определяем размер Avatar в зависимости от size компонента
	const avatarSize = size === 'default' ? 'medium' : 'small';
	// Определяем размер Informer в зависимости от size компонента
	// default → 'large', mini → 'medium'
	const informerSize = informerProps?.size || (size === 'default' ? 'large' : 'medium');

	// Создаем Avatar с правильным размером
	const avatar = (
		<Avatar
			{...avatarProps}
			size={avatarSize}
			className={classNames('dsb_avatar-text__avatar', avatarProps.className)}
		/>
	);

	// Оборачиваем Avatar в Informer, если передан informerProps
	const avatarWithInformer = informerProps ? (
		<Informer
			{...informerProps}
			size={informerSize}
			className={classNames('dsb_avatar-text__informer', informerProps.className)}
		>
			{avatar}
		</Informer>
	) : (
		avatar
	);

	return (
		<div
			{...props}
			data-testid={dataTestId}
			className={classNames('dsb_avatar-text', `dsb_avatar-text--${size}`, className)}
		>
			{avatarWithInformer}
			<div className="dsb_avatar-text__content">
				<div className="dsb_avatar-text__top-row">
					<Typography variant="body2" ellipsis className="dsb_avatar-text__label">
						{label}
					</Typography>
					{suffix && size !== 'mini' && (
						<div className="dsb_avatar-text__suffix">
							{typeof suffix === 'string' ? (
								<Typography variant="body3" ellipsis className="dsb_avatar-text__suffix-text">
									{suffix}
								</Typography>
							) : (
								suffix
							)}
						</div>
					)}
				</div>
				{description && size !== 'mini' && (
					<Typography variant="body3" inactive className="dsb_avatar-text__description">
						{description}
					</Typography>
				)}
			</div>
		</div>
	);
};
